#!/usr/bin/env bash
# test_psoma.sh — TJP test module for the Psoma pipeline
# Sourced by the test framework (tjp-test-suite). Do not execute directly.

PIPELINE_NAME="psoma"
L3_SKIP=false
L3_SKIP_REASON=""

# Synthetic FASTQ dir generated by generate_rnaseq_synthetic.sh
_PSOMA_SYNTHETIC_DIR="$SCRATCH_ROOT/pipelines/psoma/test_data/fastq"
_PSOMA_TINY_HISAT2="$REPO_ROOT/references/tiny/hisat2_index/tiny"

# ── Layer 1: offline validation ───────────────────────────────────────────────

l1_psoma() {
    local schema="$REPO_ROOT/templates/schemas/psoma.yaml"
    local tmpl="$REPO_ROOT/templates/psoma/config.yaml"
    local ss_tmpl="$REPO_ROOT/templates/psoma/samplesheet.csv"
    local tmpdir
    tmpdir=$(mktemp -d)

    # Schema and template files exist
    ts_assert_exists "psoma schema exists" "$schema"
    ts_assert_exists "psoma template config exists" "$tmpl"
    ts_assert_exists "psoma samplesheet template exists" "$ss_tmpl"

    # Required keys in template
    for key in project_name species paired_end fastq_dir samples_file \
               hisat2_index reference_gtf run_fastqc run_rna_pipeline; do
        ts_assert_yaml_key "template has '$key'" "$tmpl" "$key"
    done

    # Samplesheet template has required columns
    ts_assert_contains "samplesheet has 'sample' column"   "$ss_tmpl" "sample"
    ts_assert_contains "samplesheet has 'fastq_1' column"  "$ss_tmpl" "fastq_1"
    ts_assert_contains "samplesheet has 'fastq_2' column"  "$ss_tmpl" "fastq_2"

    # Good config (use /path/to/ placeholders for existence-checked paths)
    local good_cfg="$tmpdir/good_config.yaml"
    cat > "$good_cfg" <<YAML
project_name: Test-Psoma
species: Human
paired_end: true
fastq_dir: /path/to/fastq
samples_file: /path/to/samples.txt
hisat2_index: /path/to/hisat2_index/genome
reference_gtf: /path/to/gencode.gtf
run_fastqc: true
run_rna_pipeline: true
YAML
    ts_assert_pass "valid config passes validator" \
        bash -c "source '$REPO_ROOT/bin/lib/common.sh' && source '$REPO_ROOT/bin/lib/validate.sh' && validate_config psoma '$good_cfg'"

    # Missing hisat2_index must fail
    local bad_cfg="$tmpdir/bad_no_hisat2.yaml"
    cat > "$bad_cfg" <<YAML
project_name: Test-Psoma
species: Human
paired_end: true
fastq_dir: /path/to/fastq
samples_file: /path/to/samples.txt
reference_gtf: /path/to/gencode.gtf
run_fastqc: true
run_rna_pipeline: true
YAML
    ts_assert_fail "config missing 'hisat2_index' fails validator" \
        bash -c "source '$REPO_ROOT/bin/lib/common.sh' && source '$REPO_ROOT/bin/lib/validate.sh' && validate_config psoma '$bad_cfg'"

    # Missing samples_file must fail
    local bad_cfg2="$tmpdir/bad_no_samples.yaml"
    cat > "$bad_cfg2" <<YAML
project_name: Test-Psoma
species: Human
paired_end: true
fastq_dir: /path/to/fastq
hisat2_index: /path/to/hisat2_index/genome
reference_gtf: /path/to/gencode.gtf
run_fastqc: true
run_rna_pipeline: true
YAML
    ts_assert_fail "config missing 'samples_file' fails validator" \
        bash -c "source '$REPO_ROOT/bin/lib/common.sh' && source '$REPO_ROOT/bin/lib/validate.sh' && validate_config psoma '$bad_cfg2'"

    # Reproducibility manifest: source-snapshotting must resolve the psoma
    # submodule commit SHA. Runs fully offline, no SLURM needed.
    local mtmp
    mtmp=$(mktemp -d)
    echo "project_name: test" > "$mtmp/config.yaml"
    (
        source "$REPO_ROOT/bin/lib/common.sh"
        source "$REPO_ROOT/bin/lib/manifest.sh"
        generate_manifest "$mtmp" psoma "$mtmp/config.yaml" \
            "$REPO_ROOT/containers/psoma/psomagen_v1.0.0.sif" \
            "$REPO_ROOT/slurm_templates/psoma_slurm_template.sh"
    )
    local expected_sha
    expected_sha=$(git -C "$REPO_ROOT/containers/psoma" rev-parse HEAD 2>/dev/null)
    ts_assert_exists   "manifest: slurm_template_used.sh snapshotted" "$mtmp/slurm_template_used.sh"
    ts_assert_nonempty "manifest: pipeline_source.tar.gz snapshotted" "$mtmp/pipeline_source.tar.gz"
    ts_assert_contains "manifest: pipeline_submodule_commit matches submodule HEAD" \
        "$mtmp/manifest.json" "$expected_sha"
    rm -rf "$mtmp"

    rm -rf "$tmpdir"
}

# ── Layer 2: dry-run launch ───────────────────────────────────────────────────

l2_psoma() {
    local tmpdir
    tmpdir=$(mktemp -d)
    local fastq_dir="$tmpdir/fastq"
    local samples_txt="$tmpdir/samples.txt"
    mkdir -p "$fastq_dir"
    echo "Sample_A" > "$samples_txt"

    local cfg="$tmpdir/config.yaml"
    cat > "$cfg" <<YAML
project_name: Psoma-L2-Test
species: Human
paired_end: true
fastq_dir: $fastq_dir
samples_file: $samples_txt
hisat2_index: /path/to/hisat2_index/genome
reference_gtf: /path/to/gencode.gtf
run_fastqc: false
run_rna_pipeline: true
YAML

    ts_assert_pass "l2: config validates" \
        bash -c "source '$REPO_ROOT/bin/lib/common.sh' && source '$REPO_ROOT/bin/lib/validate.sh' && validate_config psoma '$cfg'"

    ts_assert_pass "l2: psoma in KNOWN_PIPELINES" \
        bash -c "source '$REPO_ROOT/bin/lib/common.sh' && is_known_pipeline psoma"

    ts_assert_pass "l2: SLURM template resolves" \
        bash -c "source '$REPO_ROOT/bin/lib/common.sh' && [[ -f \$(get_slurm_template psoma) ]]"

    ts_assert_fail "l2: psoma is not a native pipeline" \
        bash -c "source '$REPO_ROOT/bin/lib/common.sh' && is_native_pipeline psoma"

    # Psoma-specific: pipeline.config.tmpl must exist
    ts_assert_exists "l2: psoma pipeline.config.tmpl exists" \
        "$REPO_ROOT/templates/psoma/pipeline.config.tmpl"

    # Psoma submodule container directory must be present (submodule checked out)
    ts_assert_exists "l2: psoma submodule directory exists" \
        "$REPO_ROOT/containers/psoma"

    # Reproducibility logging: repro.sh sources cleanly and is wired into
    # the SLURM template (node/partition capture, invocation log, Nextflow trace)
    ts_assert_pass "l2: repro.sh sources cleanly" \
        bash -c "source '$REPO_ROOT/bin/lib/repro.sh'"
    ts_assert_contains "l2: psoma template sources repro.sh" \
        "$REPO_ROOT/slurm_templates/psoma_slurm_template.sh" "repro.sh"
    ts_assert_contains "l2: psoma template wraps invocation with run_logged" \
        "$REPO_ROOT/slurm_templates/psoma_slurm_template.sh" "run_logged"
    ts_assert_contains "l2: psoma template enables Nextflow trace/report" \
        "$REPO_ROOT/slurm_templates/psoma_slurm_template.sh" "with-trace"

    # Provenance README: provenance.sh sources cleanly and is wired into the
    # SLURM template (console log tee, live software-version capture,
    # PROVENANCE_README.md generated in the EXIT trap)
    ts_assert_pass "l2: provenance.sh sources cleanly" \
        bash -c "source '$REPO_ROOT/bin/lib/repro.sh' && source '$REPO_ROOT/bin/lib/provenance.sh'"
    ts_assert_pass "l2: provenance.sh defines its hooks" \
        bash -c "source '$REPO_ROOT/bin/lib/repro.sh' && source '$REPO_ROOT/bin/lib/provenance.sh' && declare -f start_console_log capture_software_versions generate_provenance_readme >/dev/null"
    ts_assert_contains "l2: psoma template sources provenance.sh" \
        "$REPO_ROOT/slurm_templates/psoma_slurm_template.sh" "provenance.sh"
    # Exact call, not just substring presence — catches argument-order bugs
    # (capture_software_versions is <run_dir> <pipeline> <primary>; a
    # regression once swapped $CONTAINER and "psoma", which matched no
    # dispatcher case arm and silently never wrote software_versions.txt).
    ts_assert_contains "l2: psoma template calls capture_software_versions with correct argument order" \
        "$REPO_ROOT/slurm_templates/psoma_slurm_template.sh" 'capture_software_versions "$RUN_DIR" "psoma" "$CONTAINER"'
    ts_assert_contains "l2: psoma template generates provenance README on exit" \
        "$REPO_ROOT/slurm_templates/psoma_slurm_template.sh" "generate_provenance_readme"

    rm -rf "$tmpdir"
}

# ── Layer 3: full SLURM execution ─────────────────────────────────────────────

l3_fixture_psoma() {
    if [[ ! -d "$_PSOMA_SYNTHETIC_DIR" ]]; then
        echo "Synthetic FASTQ dir not found: $_PSOMA_SYNTHETIC_DIR" >&2
        echo "Run: $REPO_ROOT/test_data/fixtures/generate_rnaseq_synthetic.sh $(dirname "$_PSOMA_SYNTHETIC_DIR")" >&2
        return 1
    fi

    local count
    count=$(find "$_PSOMA_SYNTHETIC_DIR" -name "*_1.fastq.gz" | wc -l)
    if [[ "$count" -eq 0 ]]; then
        echo "No *_1.fastq.gz files in $_PSOMA_SYNTHETIC_DIR (psoma uses _1/_2 suffix)" >&2
        return 1
    fi

    if [[ ! -f "${_PSOMA_TINY_HISAT2}.1.ht2" ]]; then
        echo "Tiny HISAT2 index not found: ${_PSOMA_TINY_HISAT2}.1.ht2" >&2
        echo "Build one with hisat2-build against a tiny reference (e.g., chrM only)." >&2
        return 1
    fi

    return 0
}

l3_submit_psoma() {
    local test_dir="$TEST_SCRATCH/psoma"
    local cfg="$test_dir/config_psoma.yaml"
    local samples_file="$test_dir/samples.txt"
    mkdir -p "$test_dir"

    # Build samples.txt (psoma: sample_1.fastq.gz → sample name)
    for f in "$_PSOMA_SYNTHETIC_DIR"/*_1.fastq.gz; do
        basename "$f" _1.fastq.gz
    done > "$samples_file"

    cat > "$cfg" <<YAML
project_name: Psoma-L3-Test
species: Human
paired_end: true
fastq_dir: $_PSOMA_SYNTHETIC_DIR
samples_file: $samples_file
hisat2_index: $_PSOMA_TINY_HISAT2
reference_gtf: /path/to/gencode.gtf
run_fastqc: false
run_rna_pipeline: true
YAML

    local job_id
    job_id=$("$REPO_ROOT/bin/tjp-launch" psoma --dev --config "$cfg" 2>/dev/null \
        | grep -oP '(?<=job )\d+' | tail -1)
    echo "$job_id"
}

l3_validate_psoma() {
    local runs_dir="$WORK_ROOT/pipelines/psoma/runs"
    local latest_run
    latest_run=$(ls -1td "$runs_dir"/*/ 2>/dev/null | head -1)

    if [[ -z "$latest_run" ]]; then
        ts_assert_exists "psoma: run directory exists" "$runs_dir"
        return
    fi

    ts_assert_exists "psoma: run dir created"           "$latest_run"
    ts_assert_exists "psoma: config snapshot"           "$latest_run/config.yaml"
    ts_assert_exists "psoma: manifest.json"             "$latest_run/manifest.json"
    ts_assert_exists "psoma: outputs/2_trim_output"     "$latest_run/outputs/2_trim_output"
    ts_assert_exists "psoma: outputs/3_hisat2_mapping_output" \
                     "$latest_run/outputs/3_hisat2_mapping_output"

    # Reproducibility artifacts
    ts_assert_exists   "psoma: juno_environment.json"     "$latest_run/juno_environment.json"
    ts_assert_exists   "psoma: slurm_template_used.sh"    "$latest_run/slurm_template_used.sh"
    ts_assert_nonempty "psoma: pipeline_source.tar.gz"    "$latest_run/pipeline_source.tar.gz"
    ts_assert_nonempty "psoma: invocation.log"            "$latest_run/invocation.log"
    ts_assert_contains "psoma: invocation.log records nextflow run" \
                       "$latest_run/invocation.log" "nextflow run"
    ts_assert_exists   "psoma: nextflow_logs/trace.txt"   "$latest_run/nextflow_logs/trace.txt"
    ts_assert_exists   "psoma: nextflow_logs/report.html" "$latest_run/nextflow_logs/report.html"
    ts_assert_fail     "psoma: juno_environment.json end_time populated" \
                       bash -c "grep -q '\"end_time\": null' '$latest_run/juno_environment.json'"
    ts_assert_fail     "psoma: manifest submodule commit resolved" \
                       bash -c "grep -q '\"pipeline_submodule_commit\": \"unknown\"' '$latest_run/manifest.json'"

    # Provenance README artifacts
    ts_assert_exists   "psoma: CONSOLE_LOG.txt"            "$latest_run/CONSOLE_LOG.txt"
    ts_assert_nonempty "psoma: CONSOLE_LOG.txt"            "$latest_run/CONSOLE_LOG.txt"
    ts_assert_exists   "psoma: software_versions.txt"      "$latest_run/software_versions.txt"
    ts_assert_contains "psoma: software_versions.txt has HISAT2 entry" \
                       "$latest_run/software_versions.txt" "HISAT2:"
    ts_assert_exists   "psoma: PROVENANCE_README.md"       "$latest_run/PROVENANCE_README.md"
    ts_assert_nonempty "psoma: PROVENANCE_README.md"       "$latest_run/PROVENANCE_README.md"
    ts_assert_contains "psoma: PROVENANCE_README.md has Hyperion banner" \
                       "$latest_run/PROVENANCE_README.md" "H Y P E R I O N"
    ts_assert_contains "psoma: PROVENANCE_README.md has software versions section" \
                       "$latest_run/PROVENANCE_README.md" "## 3. Software Versions"
}

l3_teardown_psoma() {
    :
}
